DO $$
DECLARE affected integer;
BEGIN
  IF (SELECT COUNT(*) FROM _adg_metadata_target_salon) <> 1 THEN
    RAISE EXCEPTION 'Expected exactly one active pinned asiandeligo channel';
  END IF;
  IF (SELECT COUNT(*) FROM _adg_metadata_decisions) <> 23 THEN
    RAISE EXCEPTION 'Expected exactly 23 metadata decisions';
  END IF;
  IF to_regclass('public.asiandeligo_catalog_metadata_product_backup_20260722') IS NOT NULL
     OR to_regclass('public.asiandeligo_catalog_metadata_audit_20260722') IS NOT NULL THEN
    RAISE EXCEPTION 'Batch backup/audit table already exists; refusing duplicate apply';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM pg_catalog.pg_trigger
    WHERE tgrelid = 'public.products'::regclass
      AND tgname = 'zz_enforce_products_monotonic_updated_at'
      AND NOT tgisinternal
      AND tgenabled <> 'D'
  ) THEN
    RAISE EXCEPTION 'Required products monotonic updated_at trigger is missing';
  END IF;

  PERFORM 1
  FROM _adg_metadata_decisions decision
  CROSS JOIN _adg_metadata_target_salon tenant
  JOIN public.product_variants variant
    ON variant.id = decision.variant_id
   AND variant.sku = decision.sku
   AND variant.salon_id = tenant.salon_id
   AND variant.is_active = TRUE
   AND variant.is_published = FALSE
   AND variant.is_for_sale = TRUE
   AND variant.sync_status = 'synced'
   AND variant.availability_status = 'IN_STOCK'
   AND variant.deleted_at IS NULL
  JOIN public.products product
    ON product.id = decision.product_id
   AND product.id = variant.template_id
   AND product.salon_id = tenant.salon_id
   AND product.name = decision.expected_name
   AND product.slug = decision.expected_slug
   AND product.updated_at = decision.expected_updated_at
   AND product.is_active = TRUE
   AND product.is_published = TRUE
   AND product.is_visible = TRUE
   AND product.status = 'active'
   AND product.deleted_at IS NULL
  JOIN public.categories category
    ON category.id = decision.category_id
   AND category.id = product.category_id
   AND category.salon_id = tenant.salon_id
   AND category.name = decision.category_name
   AND category.slug = decision.category_slug
   AND category.is_active = TRUE
  WHERE product.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure
  ORDER BY product.id
  FOR UPDATE OF product, variant, category;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 23 THEN
    RAISE EXCEPTION 'Expected 23 exact product row locks, got %', affected;
  END IF;
END $$;

CREATE TABLE public.asiandeligo_catalog_metadata_product_backup_20260722 (
  batch_key text NOT NULL CHECK (batch_key = 'asiandeligo-catalog-metadata-batch25-20260722-v1'),
  decision_sha256 text NOT NULL CHECK (decision_sha256 = '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c'),
  channel_slug text NOT NULL CHECK (channel_slug = 'asiandeligo'),
  salon_id uuid NOT NULL CHECK (salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid),
  sku text NOT NULL,
  product_id uuid NOT NULL,
  variant_id uuid NOT NULL,
  category_id uuid NOT NULL,
  changed_fields text[] NOT NULL,
  allergens jsonb,
  may_contain_allergens jsonb,
  storage_zone text,
  nutrition_facts jsonb,
  country_of_origin text,
  ingredients text,
  price_per_unit numeric,
  unit_of_measure text,
  original_updated_at timestamptz NOT NULL,
  applied_updated_at timestamptz,
  captured_at timestamptz NOT NULL DEFAULT transaction_timestamp(),
  PRIMARY KEY (batch_key, salon_id, sku),
  UNIQUE (batch_key, salon_id, product_id),
  UNIQUE (batch_key, salon_id, variant_id)
);

CREATE TABLE public.asiandeligo_catalog_metadata_audit_20260722 (
  batch_key text NOT NULL CHECK (batch_key = 'asiandeligo-catalog-metadata-batch25-20260722-v1'),
  decision_sha256 text NOT NULL CHECK (decision_sha256 = '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c'),
  channel_slug text NOT NULL CHECK (channel_slug = 'asiandeligo'),
  salon_id uuid NOT NULL CHECK (salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid),
  action text NOT NULL CHECK (action IN ('backup_captured', 'apply_complete', 'rollback_complete')),
  product_rows integer NOT NULL CHECK (product_rows = 23),
  transaction_id bigint NOT NULL DEFAULT txid_current(),
  recorded_at timestamptz NOT NULL DEFAULT transaction_timestamp(),
  PRIMARY KEY (batch_key, salon_id, action)
);

DO $$
DECLARE affected integer;
BEGIN
  INSERT INTO public.asiandeligo_catalog_metadata_product_backup_20260722 (
    batch_key, decision_sha256, channel_slug, salon_id, sku,
    product_id, variant_id, category_id, changed_fields,
    allergens, may_contain_allergens, storage_zone, nutrition_facts,
    country_of_origin, ingredients, price_per_unit, unit_of_measure,
    original_updated_at
  )
  SELECT
    'asiandeligo-catalog-metadata-batch25-20260722-v1', '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c', tenant.channel_slug, tenant.salon_id,
    decision.sku, product.id, variant.id, category.id, decision.changed_fields,
    product.allergens, product.may_contain_allergens, product.storage_zone,
    product.nutrition_facts, product.country_of_origin, product.ingredients,
    product.price_per_unit, product.unit_of_measure, product.updated_at
  FROM _adg_metadata_decisions decision
  CROSS JOIN _adg_metadata_target_salon tenant
  JOIN public.product_variants variant
    ON variant.id = decision.variant_id
   AND variant.sku = decision.sku
   AND variant.salon_id = tenant.salon_id
   AND variant.deleted_at IS NULL
  JOIN public.products product
    ON product.id = decision.product_id
   AND product.id = variant.template_id
   AND product.salon_id = tenant.salon_id
   AND product.updated_at = decision.expected_updated_at
   AND product.deleted_at IS NULL
  JOIN public.categories category
    ON category.id = decision.category_id
   AND category.id = product.category_id
   AND category.salon_id = tenant.salon_id
   AND category.is_active = TRUE
  WHERE product.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 23 THEN
    RAISE EXCEPTION 'Expected 23 persistent product backup rows, got %', affected;
  END IF;

  INSERT INTO public.asiandeligo_catalog_metadata_audit_20260722 (
    batch_key, decision_sha256, channel_slug, salon_id, action, product_rows
  )
  SELECT 'asiandeligo-catalog-metadata-batch25-20260722-v1', '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c', channel_slug, salon_id,
         'backup_captured', 23
  FROM _adg_metadata_target_salon;
END $$;

DO $$
DECLARE affected integer;
BEGIN
  UPDATE public.products product
  SET allergens = decision.target_allergens,
      may_contain_allergens = decision.target_may_contain_allergens,
      storage_zone = decision.target_storage_zone,
      nutrition_facts = decision.target_nutrition_facts,
      country_of_origin = decision.target_country_of_origin,
      ingredients = decision.target_ingredients
  FROM _adg_metadata_decisions decision,
       _adg_metadata_target_salon tenant,
       public.asiandeligo_catalog_metadata_product_backup_20260722 backup
  WHERE product.id = decision.product_id
    AND product.id = backup.product_id
    AND product.salon_id = tenant.salon_id
    AND backup.salon_id = tenant.salon_id
    AND backup.batch_key = 'asiandeligo-catalog-metadata-batch25-20260722-v1'
    AND backup.decision_sha256 = '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c'
    AND backup.sku = decision.sku
    AND product.updated_at = decision.expected_updated_at
    AND product.deleted_at IS NULL
    AND product.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 23 THEN
    RAISE EXCEPTION 'Expected 23 exact product updates, got %', affected;
  END IF;

  UPDATE public.asiandeligo_catalog_metadata_product_backup_20260722 backup
  SET applied_updated_at = product.updated_at
  FROM public.products product,
       _adg_metadata_decisions decision,
       _adg_metadata_target_salon tenant
  WHERE backup.batch_key = 'asiandeligo-catalog-metadata-batch25-20260722-v1'
    AND backup.decision_sha256 = '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c'
    AND backup.salon_id = tenant.salon_id
    AND backup.sku = decision.sku
    AND backup.product_id = product.id
    AND product.salon_id = tenant.salon_id
    AND product.updated_at > backup.original_updated_at
    AND product.deleted_at IS NULL
    AND product.allergens IS NOT DISTINCT FROM decision.target_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.target_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.target_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.target_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.target_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.target_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 23 THEN
    RAISE EXCEPTION 'Expected 23 applied updated_at captures, got %', affected;
  END IF;

  INSERT INTO public.asiandeligo_catalog_metadata_audit_20260722 (
    batch_key, decision_sha256, channel_slug, salon_id, action, product_rows
  )
  SELECT 'asiandeligo-catalog-metadata-batch25-20260722-v1', '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c', channel_slug, salon_id,
         'apply_complete', 23
  FROM _adg_metadata_target_salon;
END $$;

SELECT backup.sku, backup.changed_fields, backup.original_updated_at,
       backup.applied_updated_at, audit.transaction_id
FROM public.asiandeligo_catalog_metadata_product_backup_20260722 backup
JOIN public.asiandeligo_catalog_metadata_audit_20260722 audit
  ON audit.batch_key = backup.batch_key
 AND audit.salon_id = backup.salon_id
 AND audit.action = 'apply_complete'
WHERE backup.batch_key = 'asiandeligo-catalog-metadata-batch25-20260722-v1'
  AND backup.decision_sha256 = '0aff66c79c10e96e5ca614fa4b5a250ae4f236d784bea557a3d72fe9836d4e9c'
  AND backup.salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
ORDER BY backup.sku;

COMMIT;
